mapper.insert:
INSERT INTO symbol (imtcode, bid, ask, buy_currency, sell_currency, spread, tenor, status, valid_from, valid_till, rate_quote_id, updated_time) VALUES
(#{s.imtcode}, #{s.bid}, #{s.ask}, #{s.buyCurrency}, #{s.sellCurrency}, #{s.spread}, #{s.tenor}, #{s.status}, #{s.validFrom}, #{s.validTill}, #{s.rateQuoteID}, #{s.updatedTime})
ON CONFLICT (imtcode) DO UPDATE SET bid = EXCLUDED.bid, ask = EXCLUDED.ask, valid_from = EXCLUDED.valid_from, valid_till = EXCLUDED.valid_till, rate_quote_id = EXCLUDED.rate_quote_id, updated_time = EXCLUDED.updated_time;
